// Java
int a = 7 / 2;       // 3 — truncates toward zero
double b = 7.0 / 2;  // 3.5 — at least one float operand promotes the result

# Cyclic buffer indexing
def next_index(current, size):
    return (current + 1) % size

String s1 = new String("hello");
String s2 = new String("hello");

System.out.println(s1 == s2);       // false — different references
System.out.println(s1.equals(s2));  // true  — same content

// Nullish default (pre-nullish coalescing)
const name = user && user.name || "Anonymous";

// Modern equivalent with nullish coalescing
const name = user?.name ?? "Anonymous";

items = []
if not items:
    print("List is empty")   # Idiomatic Python empty-check

count = 0
if count:
    print("Never printed — 0 is falsy")

const name = "Ada";
const score = 99.5;
const message = `Hello, ${name}! Your score is ${score.toFixed(1)}%.`;

byte a = 100;
byte b = 100;
// byte c = a + b;  // Error! a + b is int (promoted), not byte
int c = a + b;      // OK — 200

int x = 5;
double y = 2.0;
double z = x / y;   // 2.5 — x promoted to double
int w = x / 2;      // 2   — integer division, result truncated

// if as expression
let status = if age >= 18 { "adult" } else { "minor" };

// match as expression
let description = match score {
    90..=100 => "excellent",
    70..=89  => "good",
    50..=69  => "average",
    _        => "needs improvement",
};

// Block as expression — last expression is the return value
let area = {
    let width = 4.0;
    let height = 6.0;
    width * height   // no semicolon — this is the block's value
};

let x = 5;
console.log(1 < x < 10);   // true, but for wrong reasons:
